    def _read_request_body(self, max_size=65536):
        """Safely read and parse JSON request body with size limit."""
        content_length_header = self.headers.get("Content-Length")
        if content_length_header is None:
            return None, "Missing Content-Length header"

        try:
            content_length = int(content_length_header)
        except (ValueError, TypeError):
            return None, "Invalid Content-Length header"

        if content_length < 0 or content_length > max_size:
            return None, "Content-Length must be between 0 and {}".format(max_size)

        content_type = self.headers.get("Content-Type", "")
        if "application/json" not in content_type:
            return None, "Content-Type must be application/json"

